import { Component } from '@angular/core';
import { IonicPage, NavController, NavParams } from 'ionic-angular';
import { DomSanitizer } from '@angular/platform-browser';
import { UUID } from 'angular2-uuid';
// import * as PSPDFKit from '../../assets/pspdfkit';

declare var PSPDFKit;

/**
 * Generated class for the CasepagePage page.
 *
 * See https://ionicframework.com/docs/components/#navigation for more info on
 * Ionic pages and navigation.
 */

@Component({
  selector: 'page-casefile',
  templateUrl: 'casefile.html',
})
export class CaseFilePage {

  data:any;
  sidepane: boolean;
  hamburger: boolean;
  peshi:boolean;
  baseUrl:string;
  currentPageIndex:number;
  removedItems:Array<string>;
  constructor(public navCtrl: NavController, public navParams: NavParams,public sanitizer: DomSanitizer) {
    this.currentPageIndex = 0;
    this.sidepane = false;
    this.peshi = false;
  	this.data = this.navParams.get('data');
    this.baseUrl = 'https://courtdesk.github.io';
    // this.baseUrl = 'http://127.0.0.1:7070';
    this.removedItems = ["annotate","pan","ink-signature","image","stamp","line","rectangle","arrow","ellipse","polygon","polyline"];
  	// console.dir(PSPDFKit);

  }

  ionViewDidLoad() {
    // console.log('ionViewDidLoad CasepagePage');
    this.init();
  }

  init(){
    this.sidepane = false;
    this.peshi = false;
    this.loadPDF("casefile.pdf");
  }

  loadPDF(file){
     this.clearPDF();
     let filePath = encodeURI(this.data['name'])+"/"+file;
     const defaultItems = PSPDFKit.defaultToolbarItems;
     console.log(defaultItems);

     PSPDFKit.load({
        container: "#pspdfkit",
        pdf: this.baseUrl+"/assets/docs/"+filePath,
        instantJSON : JSON.parse(localStorage.getItem(filePath)),
        licenseKey: "pSLTHKcz8tUcSuxxJyXqcCLSnzofPGJDFriLSprnRoDPK7S0F1jO9we4TB0KlG9DKTK2dx-_V8tQVXT_BvnYstUmUI2747YjeyyCh4yFS0hTvDOnkihuaDcX3MQZohJIKcT7GUZmtkmSkF_BlaGhGC8ustuTm45Dl5m1c8gxITdeWmf84LD3RAlqmQlB1JxdjED1ZbPsCt3kHQRXNR0D7vfRBY-YxQz3rxh6YUXMX1UMUBoMMdpeMRBAfCpF_jKDO5tULMA-8fs7ru5gTy-48o2l9UT1lLqEU32nCsyKldkoNopQ7JF5ezry74iw7uGEE2aIT3UApmFYoNYqi_FZy4zDCcy0RmKBrCHAIW6Q3U_FO-_8rJuhSoVSv6fTw7nGERFxh-FuoaNgPIBpC0QFGjkEZ5RhG2QnSY1-h1RWGayqEaEkja1XrQpBtvqizbxs",
        disableWebAssemblyStreaming: true
      })
        .then(instance => {
          console.log(instance);
          instance.setViewState(viewState => 
              viewState.set("sidebarMode", PSPDFKit.SidebarMode.ANNOTATIONS)
          );

          if(file==="casefile.pdf"){
            instance.setViewState(viewState => 
                viewState.set("currentPageIndex", this.currentPageIndex)
            );
          }

          instance.setToolbarItems(items =>
            items.map(item => {
              console.log(item,item.dropdownGroup);
              if(this.removedItems.indexOf(item.type)>-1)
                item.mediaQueries=['(min-width: 8000px)'];
              else
                item.mediaQueries=['(min-width: 10px)'];

              if(item.type=="ink" || item.type=="highlighter")
                item['dropdownGroup'] = UUID.UUID();
              item['responsiveGroup'] = UUID.UUID();
              return item;
            })
          );

         instance.addEventListener("viewState.change", (viewState) => {
            if(file==="casefile.pdf")
              this.currentPageIndex = viewState.get('currentPageIndex');
          });

         instance.addEventListener("annotations.didSave", async () => {
          // const instantJSON = await instance.exportInstantJSON();
          // console.log(JSON.stringify(instantJSON));
          // await fetch("http://127.0.0.1:8001", {
          //   method: "POST",
          //   headers: {
          //     "Content-Type": "application/json"
          //   },
          //   body: JSON.stringify(instantJSON)
          // });
            instance.exportInstantJSON().then(instantJSON => {
             localStorage.setItem(filePath,JSON.stringify(instantJSON));
            });
          });

          instance.addEventListener("bookmarks.didSave", async () => {
          // const instantJSON = await instance.exportInstantJSON();
          // console.log(JSON.stringify(instantJSON));
          // await fetch("http://127.0.0.1:8001", {
          //   method: "POST",
          //   headers: {
          //     "Content-Type": "application/json"
          //   },
          //   body: JSON.stringify(instantJSON)
          // });
            instance.exportInstantJSON().then(instantJSON => {
             localStorage.setItem(filePath,JSON.stringify(instantJSON));
            });
          });
        })
        .catch(error => {
          console.error(error.message);
        });
  }

  close(){
    this.navCtrl.pop();
  }

  hideBar(){
    this.sidepane=false;
    this.init();
  }

  showBar(){
    this.sidepane=true;
  }

  openCaseLaw(caselaw){
    this.peshi = false;
    this.loadPDF("Caselaw/"+caselaw)
  }

  viewPeshi(){
    this.loadPDF("peshi.pdf");
    this.peshi = true;
  }

  clearPDF() {
      const parent = document.getElementById("pspdfkit");
      while (parent.firstChild) {
          parent.firstChild['remove']();
      }
  }

  fullscreen(){
    const elem = document.getElementById("pspdfkit");
    if (elem.requestFullscreen) {
    elem.requestFullscreen();
    } else if (elem['mozRequestFullScreen']) { /* Firefox */
      elem['mozRequestFullScreen']();
    } else if (elem['webkitRequestFullscreen']) { /* Chrome, Safari and Opera */
      elem['webkitRequestFullscreen']();
    } else if (elem['msRequestFullscreen']) { /* IE/Edge */
      elem['msRequestFullscreen']();
    }
  }
}



